import axios from 'axios';

// Create axios instance with default configuration
const api = axios.create({
  baseURL: 'http://localhost:3000/api',
  withCredentials: true,
  timeout: 10000,
  headers: {
    'Content-Type': 'application/json',
  }
});

// Request interceptor to add auth token if available
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Response interceptor to handle common errors
api.interceptors.response.use(
  (response) => {
    return response;
  },
  (error) => {
    if (error.response?.status === 401) {
      // Unauthorized - clear local storage and redirect to login
      localStorage.removeItem('user');
      localStorage.removeItem('token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

// Auth API calls
export const authAPI = {
  login: (credentials) => api.post('/auth/login', credentials),
  register: (userData) => api.post('/auth/register', userData),
  logout: () => api.post('/auth/logout'),
  forgotPassword: (email) => api.post('/auth/forget-password', { email }),
};

// Dashboard API calls
export const dashboardAPI = {
  getTotalJournals: () => api.get('/dashboard/getTotalJournal'),
  getTotalStudyHours: () => api.get('/dashboard/getTotalStudyHour'),
  getRecentJournals: () => api.get('/dashboard/getRecentJournal'),
  getProductivity: () => api.get('/dashboard/productivity'),
};

// Journal API calls
export const journalAPI = {
  getAllJournals: () => api.get('/journal/allJournal'),
  createJournal: (journalData) => api.post('/journal/create-journal', journalData),
  updateJournal: (id, journalData) => api.put(`/journal/update-journal/${id}`, journalData),
  deleteJournal: (id) => api.delete(`/journal/${id}`),
  searchJournals: (params) => api.get('/journal/search', { params }),
  getSingleJournal: (id) => api.get(`/journal/singleJournal/${id}`),
};

// Profile API calls
export const profileAPI = {
  getProfile: (id) => api.get(`/profile/${id}`),
  updateProfile: (id, profileData) => api.put(`/profile/${id}`, profileData),
  changePassword: (id, passwordData) => api.put(`/profile/${id}/change-password`, passwordData),
};

export default api;
